 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$ 
<<lmain>>
declare sql_query text default '';
begin

 if coalesce(p_colm, '') <> ''
 then p_colm = ' ('||p_colm||')';
